import json
from openai import OpenAI

client = OpenAI()

def ask_approval(tool_name: str, tool_args: dict) -> bool:
    """Block until a human approves or rejects the proposed action."""
    print(f"\n[APPROVAL REQUIRED]")
    print(f"  Tool:      {tool_name}")
    print(f"  Arguments: {json.dumps(tool_args, indent=2)}")
    answer = input("  Approve? (y/n): ").strip().lower()
    return answer == "y"

def execute_hitl(tool_name: str, tool_args: dict, registry: dict) -> str:
    """Execute a tool only after explicit human approval (L2)."""
    if not ask_approval(tool_name, tool_args):
        return "Action rejected by human reviewer. Choose an alternative approach."
    try:
        return str(registry[tool_name](**tool_args))
    except Exception as exc:
        return f"Tool error: {exc}"

def run_hitl_agent(task: str, tools: dict, schemas: list, max_steps: int = 10) -> str:
    messages = [
        {"role": "system", "content": "You are a task agent. Every action will be reviewed by a human before execution."},
        {"role": "user", "content": task},
    ]
    for _ in range(max_steps):
        resp = client.chat.completions.create(model="gpt-4o", messages=messages, tools=schemas or None)
        msg = resp.choices[0].message
        messages.append(msg)
        if not msg.tool_calls:
            return msg.content
        for tc in msg.tool_calls:
            result = execute_hitl(
                tc.function.name,
                json.loads(tc.function.arguments),
                tools,
            )
            messages.append({"role": "tool", "tool_call_id": tc.id, "content": result})
    raise RuntimeError("Max steps exceeded")

from typing import Callable

# Tools considered high-risk; anything else is low-risk and runs automatically
HIGH_RISK_TOOLS = {"send_email", "delete_record", "execute_payment", "push_to_prod"}

def risk_level(tool_name: str, tool_args: dict) -> str:
    if tool_name in HIGH_RISK_TOOLS:
        return "high"
    # Heuristic: args mentioning production data or broad scope
    if any(k in str(tool_args).lower() for k in ["production", "all_users", "everyone"]):
        return "medium"
    return "low"

def escalate_to_human(tool_name: str, tool_args: dict, reason: str) -> str:
    """Route a high-risk action to a human decision channel.
    Returns the human's decision as a string the agent can act on.
    In production, replace this with a Slack/email/ticket integration.
    """
    print(f"\n[ESCALATION] Risk level requires human approval.")
    print(f"  Reason: {reason}")
    print(f"  Tool:   {tool_name}")
    print(f"  Args:   {json.dumps(tool_args, indent=2)}")
    answer = input("  Approve (y), reject (n), or modify args (m)? ").strip().lower()
    if answer == "y":
        return "approved"    # caller re-executes with original args
    if answer == "n":
        return "rejected: Human declined this action."
    return "rejected: Human requested modification; describe what to change instead."

def execute_supervised(
    tool_name: str,
    tool_args: dict,
    registry: dict,
    escalation_handler: Callable = escalate_to_human,
) -> str:
    """Execute autonomously for low-risk tools; escalate for high-risk (L4)."""
    level = risk_level(tool_name, tool_args)
    if level == "high":
        decision = escalation_handler(tool_name, tool_args, f"Tool {tool_name!r} is high-risk")
        if not decision.startswith("approved"):
            return decision
    try:
        return str(registry[tool_name](**tool_args))
    except Exception as exc:
        return f"Tool error: {exc}"

from dataclasses import dataclass
from typing import Callable, Any

@dataclass
class Tool:
    fn: Callable
    min_approval: int  # minimum autonomy level at which this tool runs without gating
                        # 2 = require HITL, 3 = HOTL, 4 = escalate if high-risk, 5 = always auto

TOOL_REGISTRY: dict[str, Tool] = {
    "web_search":   Tool(fn=web_search,   min_approval=5),  # read-only, always automatic
    "write_file":   Tool(fn=write_file,   min_approval=4),  # low-risk write, auto in L4+
    "send_email":   Tool(fn=send_email,   min_approval=2),  # irreversible, always gated at L2+
    "delete_record": Tool(fn=delete_record, min_approval=2), # destructive, always needs approval
}

AGENT_AUTONOMY_LEVEL = 4  # current deployment level

def execute_with_policy(tool_name: str, tool_args: dict) -> str:
    tool = TOOL_REGISTRY[tool_name]
    if AGENT_AUTONOMY_LEVEL < tool.min_approval:
        # Current autonomy level is too low — gate the action
        if not ask_approval(tool_name, tool_args):
            return "Action rejected by human reviewer."
    try:
        return str(tool.fn(**tool_args))
    except Exception as exc:
        return f"Error: {exc}"
